4: define('forum/topic/fork', [
5: 	'components', 'postSelect', 'alerts', 'categorySelector',
6: ], function (components, postSelect, alerts, categorySelector) {
7: 	const Fork = {};
8: 	let forkModal;
9: 	let forkCommit;
10: 	let fromTid;
11: 	let selectedCategory;
12: 
13: 	Fork.init = function () {
14: 		fromTid = ajaxify.data.tid;
15: 		selectedCategory = ajaxify.data.category;
16: 
17: 		$(window).off('action:ajaxify.end', onAjaxifyEnd).on('action:ajaxify.end', onAjaxifyEnd);
18: 
19: 		if (forkModal) {
20: 			return;
21: 		}
22: 
23: 		app.parseAndTranslate('modals/fork-topic', {
24: 			selectedCategory: selectedCategory,
25: 		}, function (html) {
26: 			forkModal = html;
27: 
28: 			forkCommit = forkModal.find('#fork_thread_commit');
29: 
30: 			$('body').append(forkModal);
31: 
32: 			categorySelector.init(forkModal.find('[component="category-selector"]'), {
33: 				onSelect: function (category) {
34: 					selectedCategory = category;
35: 				},
36: 				privilege: 'moderate',
37: 			});
38: 
39: 			forkModal.find('#fork_thread_cancel').on('click', closeForkModal);
40: 			forkModal.find('#fork-title').on('keyup', checkForkButtonEnable);
41: 
42: 			postSelect.init(function () {
43: 				checkForkButtonEnable();
44: 				showPostsSelected();
45: 			});
46: 			showPostsSelected();
47: 
48: 			forkCommit.on('click', createTopicFromPosts);
49: 		});
50: 	};
51: 
52: 	function onAjaxifyEnd() {
53: 		if (ajaxify.data.template.name !== 'topic' || ajaxify.data.tid !== fromTid) {
54: 			closeForkModal();
55: 			$(window).off('action:ajaxify.end', onAjaxifyEnd);
56: 		}
57: 	}
58: 
59: 	function createTopicFromPosts() {
60: 		if (!selectedCategory) {
61: 			return;
62: 		}
63: 		forkCommit.attr('disabled', true);
64: 		socket.emit('topics.createTopicFromPosts', {
65: 			title: forkModal.find('#fork-title').val(),
66: 			pids: postSelect.pids,
67: 			fromTid: fromTid,
68: 			cid: selectedCategory.cid,
69: 		}, function (err, newTopic) {
70: 			function fadeOutAndRemove(pid) {
71: 				components.get('post', 'pid', pid).fadeOut(500, function () {
72: 					$(this).remove();
73: 				});
74: 			}
75: 			forkCommit.removeAttr('disabled');
76: 			if (err) {
77: 				return alerts.error(err.message);
78: 			}
79: 
80: 			alerts.alert({
81: 				timeout: 5000,
82: 				title: '[[global:alert.success]]',
83: 				message: '[[topic:fork-success]]',
84: 				type: 'success',
85: 				clickfn: function () {
86: 					ajaxify.go('topic/' + newTopic.slug);
87: 				},
88: 			});
89: 
90: 			postSelect.pids.forEach(function (pid) {
91: 				fadeOutAndRemove(pid);
92: 			});
93: 
94: 			closeForkModal();
95: 		});
96: 	}
97: 
98: 	function showPostsSelected() {
99: 		if (postSelect.pids.length) {
100: 			forkModal.find('#fork-pids').translateHtml('[[topic:fork-pid-count, ' + postSelect.pids.length + ']]');
101: 		} else {
102: 			forkModal.find('#fork-pids').translateHtml('[[topic:fork-no-pids]]');
103: 		}
104: 	}
105: 
106: 	function checkForkButtonEnable() {
107: 		if (forkModal.find('#fork-title').val().length && postSelect.pids.length) {
108: 			forkCommit.removeAttr('disabled');
109: 		} else {
110: 			forkCommit.attr('disabled', true);
111: 		}
112: 	}
113: 
114: 	function closeForkModal() {
115: 		if (forkModal) {
116: 			forkModal.remove();
117: 			forkModal = null;
118: 			postSelect.disable();
119: 		}
120: 	}
121: 
122: 	return Fork;
123: });
