4: define('notifications', [
5: 	'translator',
6: 	'components',
7: 	'navigator',
8: 	'tinycon',
9: 	'hooks',
10: 	'alerts',
11: ], function (translator, components, navigator, Tinycon, hooks, alerts) {
12: 	const Notifications = {};
13: 
14: 	let unreadNotifs = {};
15: 
16: 	const _addTimeagoString = ({ notifications: notifs }) => new Promise((resolve) => {
17: 		for (let i = 0; i < notifs.length; i += 1) {
18: 			notifs[i].timeagoLong = $.timeago(new Date(parseInt(notifs[i].datetime, 10)));
19: 		}
20: 		translator.toggleTimeagoShorthand(function () {
21: 			for (let i = 0; i < notifs.length; i += 1) {
22: 				notifs[i].timeago = $.timeago(new Date(parseInt(notifs[i].datetime, 10)));
23: 				notifs[i].timeagoShort = notifs[i].timeago;
24: 			}
25: 			translator.toggleTimeagoShorthand();
26: 			resolve({ notifications: notifs });
27: 		});
28: 	});
29: 	hooks.on('filter:notifications.load', _addTimeagoString);
30: 
31: 	Notifications.loadNotifications = function (notifList, callback) {
32: 		callback = callback || function () {};
33: 		socket.emit('notifications.get', null, function (err, data) {
34: 			if (err) {
35: 				return alerts.error(err);
36: 			}
37: 
38: 			const notifs = data.unread.concat(data.read).sort(function (a, b) {
39: 				return parseInt(a.datetime, 10) > parseInt(b.datetime, 10) ? -1 : 1;
40: 			});
41: 
42: 			hooks.fire('filter:notifications.load', { notifications: notifs }).then(({ notifications }) => {
43: 				app.parseAndTranslate('partials/notifications_list', { notifications }, function (html) {
44: 					notifList.html(html);
45: 					notifList.off('click').on('click', '[data-nid]', function (ev) {
46: 						const notifEl = $(this);
47: 						if (scrollToPostIndexIfOnPage(notifEl)) {
48: 							ev.stopPropagation();
49: 							ev.preventDefault();
50: 							components.get('notifications/list').dropdown('toggle');
51: 						}
52: 
53: 						const unread = notifEl.hasClass('unread');
54: 						if (!unread) {
55: 							return;
56: 						}
57: 						const nid = notifEl.attr('data-nid');
58: 						markNotification(nid, true);
59: 					});
60: 					components.get('notifications').on('click', '.mark-all-read', Notifications.markAllRead);
61: 
62: 					Notifications.handleUnreadButton(notifList);
63: 
64: 					hooks.fire('action:notifications.loaded', {
65: 						notifications: notifs,
66: 						list: notifList,
67: 					});
68: 					callback();
69: 				});
70: 			});
71: 		});
72: 	};
73: 
74: 	Notifications.handleUnreadButton = function (notifList) {
75: 		notifList.on('click', '.mark-read', function () {
76: 			const $this = $(this);
77: 			const notifEl = $this.parents('[data-nid]');
78: 			const unread = notifEl.hasClass('unread');
79: 			const nid = notifEl.attr('data-nid');
80: 			markNotification(nid, unread, function () {
81: 				notifEl.toggleClass('unread');
82: 				$this.find('.unread').toggleClass('hidden', unread);
83: 				$this.find('.read').toggleClass('hidden', !unread);
84: 			});
85: 			return false;
86: 		});
87: 	};
88: 
89: 	Notifications.onNewNotification = function (notifData) {
90: 		if (ajaxify.currentPage === 'notifications') {
91: 			ajaxify.refresh();
92: 		}
93: 		if (ajaxify.data.template.chats && parseInt(ajaxify.data.roomId, 10) === parseInt(notifData.roomId, 10)) {
94: 			return;
95: 		}
96: 
97: 		socket.emit('notifications.getCount', function (err, count) {
98: 			if (err) {
99: 				return alerts.error(err);
100: 			}
101: 
102: 			Notifications.updateNotifCount(count);
103: 		});
104: 
105: 		if (!unreadNotifs[notifData.nid]) {
106: 			unreadNotifs[notifData.nid] = true;
107: 		}
108: 	};
109: 
110: 	Notifications.markNotification = function (nid, read, callback) {
111: 		markNotification(nid, read, callback);
112: 	};
113: 
114: 	function markNotification(nid, read, callback) {
115: 		socket.emit('notifications.mark' + (read ? 'Read' : 'Unread'), nid, function (err) {
116: 			if (err) {
117: 				return alerts.error(err);
118: 			}
119: 
120: 			if (read && unreadNotifs[nid]) {
121: 				delete unreadNotifs[nid];
122: 			}
123: 			if (callback) {
124: 				callback();
125: 			}
126: 		});
127: 	}
128: 
129: 	function scrollToPostIndexIfOnPage(notifEl) {
130: 		// Scroll to index if already in topic (gh#5873)
131: 		const pid = notifEl.attr('data-pid');
132: 		const path = notifEl.attr('data-path');
133: 		const postEl = components.get('post', 'pid', pid);
134: 		if (path.startsWith(config.relative_path + '/post/') && pid && postEl.length && ajaxify.data.template.topic) {
135: 			navigator.scrollToIndex(postEl.attr('data-index'), true);
136: 			return true;
137: 		}
138: 		return false;
139: 	}
140: 
141: 	Notifications.updateNotifCount = function (count) {
142: 		const notifIcon = components.get('notifications/icon');
143: 		count = Math.max(0, count);
144: 		notifIcon.toggleClass('fa-bell', count > 0)
145: 			.toggleClass('fa-bell-o', count <= 0);
146: 
147: 		const countText = count > 99 ? '99+' : count;
148: 		notifIcon.toggleClass('unread-count', count > 0);
149: 		notifIcon.attr('data-content', countText);
150: 		components.get('notifications/count').toggleClass('hidden', count <= 0).text(countText);
151: 		const payload = {
152: 			count: count,
153: 			updateFavicon: true,
154: 		};
155: 		hooks.fire('action:notification.updateCount', payload);
156: 
157: 		if (payload.updateFavicon) {
158: 			Tinycon.setBubble(countText);
159: 		}
160: 
161: 		if (navigator.setAppBadge) { // feature detection
162: 			navigator.setAppBadge(count);
163: 		}
164: 	};
165: 
166: 	Notifications.markAllRead = function () {
167: 		socket.emit('notifications.markAllRead', function (err) {
168: 			if (err) {
169: 				alerts.error(err);
170: 			}
171: 			unreadNotifs = {};
172: 			const notifEls = $('[component="notifications/list"] [data-nid]');
173: 			notifEls.removeClass('unread');
174: 			notifEls.find('.mark-read .unread').addClass('hidden');
175: 			notifEls.find('.mark-read .read').removeClass('hidden');
176: 		});
177: 	};
178: 
179: 	return Notifications;
180: });
