4: define('forum/topic/postTools', [
5: 	'share',
6: 	'navigator',
7: 	'components',
8: 	'translator',
9: 	'forum/topic/votes',
10: 	'api',
11: 	'bootbox',
12: 	'alerts',
13: 	'hooks',
14: 	'helpers',
15: ], function (share, navigator, components, translator, votes, api, bootbox, alerts, hooks, helpers) {
16: 	const PostTools = {};
17: 
18: 	let staleReplyAnyway = false;
19: 
20: 	PostTools.init = function (tid) {
21: 		staleReplyAnyway = false;
22: 
23: 		renderMenu();
24: 
25: 		addPostHandlers(tid);
26: 
27: 		share.addShareHandlers(ajaxify.data.titleRaw);
28: 
29: 		votes.addVoteHandler();
30: 
31: 		PostTools.updatePostCount(ajaxify.data.postcount);
32: 	};
33: 
34: 	function renderMenu() {
35: 		const container = document.querySelector('[component="topic"]');
36: 		if (!container) {
37: 			return;
38: 		}
39: 		$('[component="topic"]').on('show.bs.dropdown', '[component="post/tools"]', function () {
40: 			const $this = $(this);
41: 			const dropdownMenu = $this.find('.dropdown-menu');
42: 			const { top } = this.getBoundingClientRect();
43: 			$this.toggleClass('dropup', top > window.innerHeight / 2);
44: 
45: 			if (dropdownMenu.attr('data-loaded')) {
46: 				return;
47: 			}
48: 			dropdownMenu.html(helpers.generatePlaceholderWave([
49: 				3, 5, 9, 7, 10, 'divider', 10,
50: 			]));
51: 
52: 			const postEl = $this.parents('[data-pid]');
53: 			const pid = postEl.attr('data-pid');
54: 			const index = parseInt(postEl.attr('data-index'), 10);
55: 
56: 			socket.emit('posts.loadPostTools', { pid: pid }, async (err, data) => {
57: 				if (err) {
58: 					return alerts.error(err);
59: 				}
60: 				data.posts.display_move_tools = data.posts.display_move_tools && index !== 0;
61: 
62: 				const html = await app.parseAndTranslate('partials/topic/post-menu-list', data);
63: 				const clipboard = require('clipboard');
64: 
65: 				dropdownMenu.attr('data-loaded', 'true').html(html);
66: 
67: 				new clipboard('[data-clipboard-text]');
68: 
69: 				hooks.fire('action:post.tools.load', {
70: 					element: dropdownMenu,
71: 				});
72: 			});
73: 		});
74: 	}
75: 
76: 	PostTools.toggle = function (pid, isDeleted) {
77: 		const postEl = components.get('post', 'pid', pid);
78: 
79: 		postEl.find('[component="post/quote"], [component="post/bookmark"], [component="post/reply"], [component="post/flag"], [component="user/chat"]')
80: 			.toggleClass('hidden', isDeleted);
81: 
82: 		postEl.find('[component="post/delete"]').toggleClass('hidden', isDeleted).parent().attr('hidden', isDeleted ? '' : null);
83: 		postEl.find('[component="post/restore"]').toggleClass('hidden', !isDeleted).parent().attr('hidden', !isDeleted ? '' : null);
84: 		postEl.find('[component="post/purge"]').toggleClass('hidden', !isDeleted).parent().attr('hidden', !isDeleted ? '' : null);
85: 
86: 		PostTools.removeMenu(postEl);
87: 	};
88: 
89: 	PostTools.removeMenu = function (postEl) {
90: 		postEl.find('[component="post/tools"] .dropdown-menu')
91: 			.removeAttr('data-loaded').html('');
92: 	};
93: 
94: 	PostTools.updatePostCount = function (postCount) {
95: 		const postCountEl = components.get('topic/post-count');
96: 		postCountEl.attr('title', postCount)
97: 			.html(helpers.humanReadableNumber(postCount));
98: 		navigator.setCount(postCount);
99: 	};
100: 
101: 	function addPostHandlers(tid) {
102: 		const postContainer = components.get('topic');
103: 
104: 		handleSelectionTooltip();
105: 
106: 		postContainer.on('click', '[component="post/quote"]', function () {
107: 			onQuoteClicked($(this), tid);
108: 		});
109: 
110: 		postContainer.on('click', '[component="post/reply"]', function () {
111: 			onReplyClicked($(this), tid);
112: 		});
113: 
114: 		$('.topic').on('click', '[component="topic/reply"]', function (e) {
115: 			e.preventDefault();
116: 			onReplyClicked($(this), tid);
117: 		});
118: 
119: 		$('.topic').on('click', '[component="topic/reply-as-topic"]', function () {
120: 			translator.translate(`[[topic:link-back, ${ajaxify.data.titleRaw}, ${config.relative_path}/topic/${ajaxify.data.slug}]]`, function (body) {
121: 				hooks.fire('action:composer.topic.new', {
122: 					cid: ajaxify.data.cid,
123: 					body: body,
124: 				});
125: 			});
126: 		});
127: 
128: 		postContainer.on('click', '[component="post/bookmark"]', function () {
129: 			return bookmarkPost($(this), getData($(this), 'data-pid'));
130: 		});
131: 
132: 		postContainer.on('click', '[component="post/upvote"]', function () {
133: 			return votes.toggleVote($(this), '.upvoted', 1);
134: 		});
135: 
136: 		postContainer.on('click', '[component="post/downvote"]', function () {
137: 			return votes.toggleVote($(this), '.downvoted', -1);
138: 		});
139: 
140: 		postContainer.on('click', '[component="post/vote-count"]', function () {
141: 			votes.showVotes(getData($(this), 'data-pid'));
142: 		});
143: 
144: 		postContainer.on('click', '[component="post/announce-count"]', function () {
145: 			votes.showAnnouncers(getData($(this), 'data-pid'));
146: 		});
147: 
148: 		postContainer.on('click', '[component="post/flag"]', function () {
149: 			const pid = getData($(this), 'data-pid');
150: 			require(['flags'], function (flags) {
151: 				flags.showFlagModal({
152: 					type: 'post',
153: 					id: pid,
154: 				});
155: 			});
156: 		});
157: 
158: 		postContainer.on('click', '[component="post/already-flagged"]', function () {
159: 			const flagId = $(this).data('flag-id');
160: 			require(['flags'], function (flags) {
161: 				bootbox.confirm('[[flags:modal-confirm-rescind]]', function (confirm) {
162: 					if (!confirm) {
163: 						return;
164: 					}
165: 					flags.rescind(flagId);
166: 				});
167: 			});
168: 		});
169: 
170: 		postContainer.on('click', '[component="post/flagUser"]', function () {
171: 			const uid = getData($(this), 'data-uid');
172: 			require(['flags'], function (flags) {
173: 				flags.showFlagModal({
174: 					type: 'user',
175: 					id: uid,
176: 				});
177: 			});
178: 		});
179: 
180: 		postContainer.on('click', '[component="post/flagResolve"]', function () {
181: 			const flagId = $(this).attr('data-flagId');
182: 			require(['flags'], function (flags) {
183: 				flags.resolve(flagId);
184: 			});
185: 		});
186: 
187: 		postContainer.on('click', '[component="post/edit"]', function () {
188: 			const btn = $(this);
189: 
190: 			const timestamp = parseInt(getData(btn, 'data-timestamp'), 10);
191: 			const postEditDuration = parseInt(ajaxify.data.postEditDuration, 10);
192: 
193: 			if (checkDuration(postEditDuration, timestamp, 'post-edit-duration-expired')) {
194: 				hooks.fire('action:composer.post.edit', {
195: 					pid: getData(btn, 'data-pid'),
196: 				});
197: 			}
198: 		});
199: 
200: 		if (config.enablePostHistory && ajaxify.data.privileges['posts:history']) {
201: 			postContainer.on('click', '[component="post/view-history"], [component="post/edit-indicator"]', function () {
202: 				const btn = $(this);
203: 				require(['forum/topic/diffs'], function (diffs) {
204: 					diffs.open(getData(btn, 'data-pid'));
205: 				});
206: 			});
207: 		}
208: 
209: 		postContainer.on('click', '[component="post/delete"]', function () {
210: 			const btn = $(this);
211: 			const timestamp = parseInt(getData(btn, 'data-timestamp'), 10);
212: 			const postDeleteDuration = parseInt(ajaxify.data.postDeleteDuration, 10);
213: 			if (checkDuration(postDeleteDuration, timestamp, 'post-delete-duration-expired')) {
214: 				togglePostDelete($(this));
215: 			}
216: 		});
217: 
218: 		function checkDuration(duration, postTimestamp, languageKey) {
219: 			if (!ajaxify.data.privileges.isAdminOrMod && duration && Date.now() - postTimestamp > duration * 1000) {
220: 				const numDays = Math.floor(duration / 86400);
221: 				const numHours = Math.floor((duration % 86400) / 3600);
222: 				const numMinutes = Math.floor(((duration % 86400) % 3600) / 60);
223: 				const numSeconds = ((duration % 86400) % 3600) % 60;
224: 				let msg = '[[error:' + languageKey + ', ' + duration + ']]';
225: 				if (numDays) {
226: 					if (numHours) {
227: 						msg = '[[error:' + languageKey + '-days-hours, ' + numDays + ', ' + numHours + ']]';
228: 					} else {
229: 						msg = '[[error:' + languageKey + '-days, ' + numDays + ']]';
230: 					}
231: 				} else if (numHours) {
232: 					if (numMinutes) {
233: 						msg = '[[error:' + languageKey + '-hours-minutes, ' + numHours + ', ' + numMinutes + ']]';
234: 					} else {
235: 						msg = '[[error:' + languageKey + '-hours, ' + numHours + ']]';
236: 					}
237: 				} else if (numMinutes) {
238: 					if (numSeconds) {
239: 						msg = '[[error:' + languageKey + '-minutes-seconds, ' + numMinutes + ', ' + numSeconds + ']]';
240: 					} else {
241: 						msg = '[[error:' + languageKey + '-minutes, ' + numMinutes + ']]';
242: 					}
243: 				}
244: 				alerts.error(msg);
245: 				return false;
246: 			}
247: 			return true;
248: 		}
249: 
250: 		postContainer.on('click', '[component="post/restore"]', function () {
251: 			togglePostDelete($(this));
252: 		});
